# Import libraries
from cpmpy import *
import json

a = 1;
b = 2;
c = 3;
d = 4;
e = 5;
f = 6;
g = 7;
h = 8;
i = 9;
j = 10;
k = 11;
l = 12;
m = 13;
n = 14;
o = 15;
p = 16;
q = 17;
r = 18;
s = 19;
t = 20;
u = 21;
v = 22;
w = 23;
x = 24;
y = 25;
z = 26;

AA = [
    [h, o, s, e, s],  # HOSES
    [l, a, s, e, r],  # LASER
    [s, a, i, l, s],  # SAILS
    [s, h, e, e, t],  # SHEET
    [s, t, e, e, r],  # STEER
    [h, e, e, l, 0],  # HEEL
    [h, i, k, e, 0],  # HIKE
    [k, e, e, l, 0],  # KEEL
    [k, n, o, t, 0],  # KNOT
    [l, i, n, e, 0],  # LINE
    [a, f, t, 0, 0],  # AFT
    [a, l, e, 0, 0],  # ALE
    [e, e, l, 0, 0],  # EEL
    [l, e, e, 0, 0],  # LEE
    [t, i, e, 0, 0]  # TIE
]
word_len = 5
num_words = len(AA)

num_overlapping = 12
overlapping = [
    [0, 2, 1, 0],  # s
    [0, 4, 2, 0],  # s

    [3, 1, 1, 2],  # i
    [3, 2, 4, 0],  # k
    [3, 3, 2, 2],  # e

    [6, 0, 1, 3],  # l
    [6, 1, 4, 1],  # e
    [6, 2, 2, 3],  # e

    [7, 0, 5, 1],  # l
    [7, 2, 1, 4],  # s
    [7, 3, 4, 2],  # e
    [7, 4, 2, 4]  # r
]

A = intvar(0, 26, shape=(num_words, word_len), name="A")

n = 8
E = intvar(0, num_words, shape=n, name="E")  # The selected words for each slot

model = Model()

for I in range(num_words):
    for J in range(word_len):
        model += [A[I, J] == AA[I][J]]

model += [AllDifferent(E)]

for I in range(num_overlapping):
    model += [A[E[overlapping[I][0]], overlapping[I][1]] == A[E[overlapping[I][2]], overlapping[I][3]]]

model.solve()

# Print the solution
solution = {"E": E.value().tolist()}
print(json.dumps(solution))
# End of CPMPy script

# Import libraries
from cpmpy import *
import json

M = len(board)
N = len(board[0])
B = intvar(1, 10, shape=(M, N), name="B")

model = Model()

for i in range(M):
    for j in range(N):
        same_neighs_ij = sum([B[i][j] == B[k][l]
                              for k in range(M) for l in range(N) if abs(k - i) + abs(l - j) == 1])
        if board[i][j] != 0:
            model += [B[i, j] == board[i][j]]
            model += [same_neighs_ij == 1]
        else:
            model += [(same_neighs_ij == 2) | (B[i][j] == 0)]

model.solve()

solution = {"B": B.value().tolist()}
print(json.dumps(solution))
# End of CPMPy script

