% Strategy: dual-variable reformulation with an auxiliary total-corn equation; preserve exact feasibility while changing from direct person-count sum to derived children count.
var 0..100: men;
var 0..100: women;
var 0..100: children;

constraint women = 5 * men;
constraint 3 * men + 2 * women + 0.5 * children = 100;
constraint men + women + children = 100;

solve satisfy;

output ["{\"men\": ", show(men), ", \"women\": ", show(women), ", \"children\": ", show(children), "}"];

