equivalent.code:
% Strategy: encode each operation sequence as a permutation variable with a transition table, and model the two age computations as separate state chains; enforce that the two permutations are not identical, preserving exactly the same feasible (m,h) pairs as the reference.
include "globals.mzn";

int: age_low = 16;
int: age_high = 120;

var age_low..age_high: m;
var age_low..age_high: h;

array[1..4] of var 0..3: perm1;
array[1..4] of var 0..3: perm2;

array[1..5] of var 1..1000: mseq;
array[1..5] of var 1..1000: hseq;

constraint all_different(perm1);
constraint all_different(perm2);

constraint exists(i in 1..4)(perm1[i] != perm2[i]);

constraint mseq[1] == m;
constraint hseq[1] == h;
constraint mseq[5] == h;
constraint hseq[5] == m;

constraint forall(i in 1..4)(
    (perm1[i] == 0 -> mseq[i+1] == mseq[i] + 2) /\
    (perm1[i] == 1 -> 8 * mseq[i+1] == mseq[i]) /\
    (perm1[i] == 2 -> mseq[i+1] == mseq[i] - 3) /\
    (perm1[i] == 3 -> mseq[i+1] == mseq[i] * 7)
);

constraint forall(i in 1..4)(
    (perm2[i] == 0 -> hseq[i+1] == hseq[i] + 2) /\
    (perm2[i] == 1 -> 8 * hseq[i+1] == hseq[i]) /\
    (perm2[i] == 2 -> hseq[i+1] == hseq[i] - 3) /\
    (perm2[i] == 3 -> hseq[i+1] == hseq[i] * 7)
);

solve satisfy;

output ["{\"m\": ", show(m), ", \"h\": ", show(h), "}"];

