# Strategy: introduce pairwise shared-ring helper variables to reify common-ring membership, preserving exact feasibility while strengthening propagation.
import cpmpy as cp
import json
import numpy as np

model = cp.Model()

ring_config = cp.boolvar(shape=(r, n), name="ring_config")
shared = cp.boolvar(shape=(r, n, n), name="shared")

for k in range(r):
    for i in range(n):
        for j in range(i + 1, n):
            model += shared[k, i, j] <= ring_config[k, i]
            model += shared[k, i, j] <= ring_config[k, j]
            model += shared[k, i, j] >= ring_config[k, i] + ring_config[k, j] - 1

for i in range(n):
    for j in range(i + 1, n):
        if demand[i][j] > 0:
            model += cp.sum(shared[:, i, j]) >= 1
        else:
            model += cp.sum(shared[:, i, j]) >= 0

for k in range(r):
    model += cp.sum(ring_config[k, :]) <= capacity_nodes[k]

total_adms = cp.sum(ring_config)
model.minimize(total_adms)

if model.solve():
    solution = {
        "ring_config": ring_config.value().tolist(),
        "total_adms": int(model.objective_value())
    }
    print(json.dumps(solution))
else:
    print("No solution found.")

